import anthropic
from dataclasses import dataclass
from enum import Enum


class Tier(Enum):
    CHEAP = "cheap"       # simple extraction, classification, reformatting
    MID = "mid"           # single-step reasoning, summarization
    PREMIUM = "premium"   # multi-step reasoning, complex analysis, code generation


# Map each tier to a model. Adjust to your provider's current offerings.
MODEL_MAP = {
    Tier.CHEAP:   "claude-haiku-4-5",
    Tier.MID:     "claude-sonnet-4-5",
    Tier.PREMIUM: "claude-opus-4-5",
}

# Approximate cost per 1M tokens (input/output) — update from provider pricing page
COST_PER_1M = {
    "claude-haiku-4-5":  {"input": 0.80,  "output": 4.00},
    "claude-sonnet-4-5": {"input": 3.00,  "output": 15.0},
    "claude-opus-4-5":   {"input": 15.0,  "output": 75.0},
}


@dataclass
class RoutingDecision:
    tier: Tier
    model: str
    reason: str


def classify_task(task: str, context_turns: int, tool_count: int) -> RoutingDecision:
    """Rule-based classifier. Replace with an ML classifier for more precision."""
    task_lower = task.lower()

    # Heuristic: tasks with many tools, many turns, or explicit reasoning keywords
    complex_keywords = {"reason", "analyze", "compare", "design", "architect", "generate code"}
    if tool_count > 5 or context_turns > 10 or any(k in task_lower for k in complex_keywords):
        return RoutingDecision(Tier.PREMIUM, MODEL_MAP[Tier.PREMIUM], "complex reasoning task")

    mid_keywords = {"summarize", "explain", "describe", "evaluate"}
    if any(k in task_lower for k in mid_keywords):
        return RoutingDecision(Tier.MID, MODEL_MAP[Tier.MID], "mid-tier reasoning")

    return RoutingDecision(Tier.CHEAP, MODEL_MAP[Tier.CHEAP], "simple extraction / classification")


def routed_call(task: str, context_turns: int = 0, tool_count: int = 0) -> dict:
    """Route a task to the cheapest capable model and return the response."""
    decision = classify_task(task, context_turns, tool_count)
    print(f"[Router] Tier={decision.tier.value} Model={decision.model} Reason={decision.reason}")

    client = anthropic.Anthropic()
    response = client.messages.create(
        model=decision.model,
        max_tokens=512,
        messages=[{"role": "user", "content": task}],
    )

    # Estimate cost
    usage = response.usage
    prices = COST_PER_1M[decision.model]
    cost = (usage.input_tokens / 1_000_000 * prices["input"]
            + usage.output_tokens / 1_000_000 * prices["output"])
    print(f"[Router] Estimated cost: ${cost:.6f}")
    return {"model": decision.model, "cost": cost, "response": response}


# Simple task → cheap model
routed_call("Extract the country name from: 'The summit was held in Vienna.'")

# Reasoning task → mid or premium model
routed_call("Analyze the trade-offs between microservices and monolithic architectures.",
            tool_count=0)

# Complex multi-step → premium model
routed_call("Design a fault-tolerant data pipeline for 1M events/day.",
            context_turns=12, tool_count=8)

import datetime

# WRONG: timestamp inside the cached prefix
system_wrong = [
    {
        "type": "text",
        # Including a dynamic value before cache_control invalidates the cache every call
        "text": f"Current time: {datetime.datetime.now()}\n\nYou are an expert assistant...",
        "cache_control": {"type": "ephemeral"},
    }
]

# CORRECT: dynamic values go in the user message, after the stable cached prefix
system_correct = [
    {
        "type": "text",
        "text": "You are an expert assistant...",  # stable — same every call
        "cache_control": {"type": "ephemeral"},
    }
]
user_message_with_context = {
    "role": "user",
    "content": f"[Context: {datetime.datetime.now()}]\n\nUser question here.",
}

# WRONG: routing by input length
def classify_wrong(prompt: str) -> str:
    if len(prompt) < 500:
        return "claude-haiku-4-5"   # short = cheap? Not true
    return "claude-opus-4-5"


# CORRECT: route by task type with a keyword/intent classifier
def classify_correct(task: str) -> str:
    reasoning_signals = {"design", "architect", "tradeoff", "compare", "generate code"}
    if any(signal in task.lower() for signal in reasoning_signals):
        return "claude-opus-4-5"
    extraction_signals = {"extract", "list", "find", "what is", "who is"}
    if any(signal in task.lower() for signal in extraction_signals):
        return "claude-haiku-4-5"
    return "claude-sonnet-4-5"  # default mid-tier for ambiguous tasks

# Using the Anthropic Batch API for non-interactive workflows
import anthropic
import json

client = anthropic.Anthropic()

# Prepare a batch of extraction tasks
documents = [
    "Contract A: Term 12 months, value $50,000, party Acme Corp...",
    "Contract B: Term 6 months, value $25,000, party Beta Ltd...",
    "Contract C: Term 24 months, value $120,000, party Gamma Inc...",
]

requests = [
    {
        "custom_id": f"contract-{i}",
        "params": {
            "model": "claude-haiku-4-5",
            "max_tokens": 256,
            "messages": [
                {
                    "role": "user",
                    "content": (
                        f"Extract term, value, and party from:\n\n{doc}\n"
                        f"Return JSON: {{\"term\": ..., \"value\": ..., \"party\": ...}}"
                    ),
                }
            ],
        },
    }
    for i, doc in enumerate(documents)
]

# Submit the batch (processed asynchronously, typically minutes to hours)
batch = client.messages.batches.create(requests=requests)
print(f"Batch ID: {batch.id}  Status: {batch.processing_status}")

# Poll for completion (in production, use a webhook or scheduled check)
import time
while True:
    batch = client.messages.batches.retrieve(batch.id)
    print(f"Status: {batch.processing_status}")
    if batch.processing_status == "ended":
        break
    time.sleep(10)

# Retrieve results
for result in client.messages.batches.results(batch.id):
    print(f"ID: {result.custom_id}  Result: {result.result.message.content[0].text[:80]}")
